mapper.select:
SELECT id, name, code, module, type, description, parent_id, sort_order, is_deleted, create_name, create_id, create_date, update_name, update_id, update_date FROM sp_permission WHERE is_deleted = 0
AND module = #{module}
ORDER BY parent_id, sort_order, create_date DESC

mapper.update:
UPDATE sp_permission
name = #{name}, code = #{code}, module = #{module}, type = #{type}, description = #{description}, parent_id = #{parentId}, sort_order = #{sortOrder}, update_name = #{updateName}, update_id = #{updateId},
WHERE id = #{id}

mapper.select:
SELECT p.id, p.name, p.code, p.module, p.type, p.description, p.parent_id, p.sort_order, p.is_deleted, p.create_name, p.create_id, p.create_date, p.update_name, p.update_id, p.update_date FROM sp_permission p LEFT JOIN sp_role_permission rp ON p.id = rp.permission_id WHERE rp.role_id IN
#{roleId}
AND p.is_deleted = 0
